<script setup lang="ts">
import{useQuery}from'@tanstack/vue-query';import{Clock3,RefreshCw,Workflow}from'lucide-vue-next';import Button from'@/components/ui/Button.vue';import StatusBadge from'@/components/ui/StatusBadge.vue';import{getJobs}from'@/lib/api';const query=useQuery({queryKey:['jobs'],queryFn:getJobs,refetchInterval:2500});const tone=(status:string)=>status==='succeeded'?'healthy':status==='failed'?'critical':status==='running'?'info':'warning'
</script><template><div class="mx-auto max-w-[1680px] space-y-5"><header class="flex items-end justify-between"><div><div class="flex items-center gap-2 font-mono text-[10px] uppercase tracking-widest text-signal"><Workflow class="h-3.5 w-3.5"/>Fila durável no PostgreSQL</div><h1 class="mt-3 text-3xl font-semibold tracking-tight">Tarefas e workers</h1><p class="mt-2 text-sm text-muted">Reserva concorrente SKIP LOCKED, nova tentativa exponencial e execução fora da requisição.</p></div><Button variant="outline" @click="query.refetch()"><RefreshCw class="h-4 w-4"/>Atualizar</Button></header><section class="overflow-hidden rounded-xl border border-line bg-panel/65"><div class="divide-y divide-line/60"><article v-for="job in query.data.value" :key="job.id" class="grid gap-3 px-5 py-4 md:grid-cols-[1fr_130px_120px_170px]"><div class="flex gap-3"><div class="grid h-9 w-9 shrink-0 place-items-center rounded-lg border border-line bg-slate-950/50"><Clock3 class="h-4 w-4 text-muted"/></div><div><p class="text-sm text-slate-200">{{job.kind}}</p><p class="mt-1 font-mono text-[9px] text-muted">{{job.id}}</p><p v-if="job.last_error" class="mt-2 text-[11px] text-danger">{{job.last_error}}</p></div></div><div class="self-center"><StatusBadge :status="tone(job.status)" :label="job.status"/></div><p class="self-center font-mono text-[10px] text-muted">TENTATIVA {{job.attempts}}/{{job.max_attempts}}</p><time class="self-center text-xs text-muted">{{new Date(job.created_at).toLocaleString('pt-BR')}}</time></article><div v-if="!query.data.value?.length" class="p-14 text-center text-sm text-muted">Fila vazia.</div></div></section></div></template>

